mapper.select:
SELECT COUNT(*) /* com.flowenect.hr.eval.mapper.EvalMapper.checkExistEval */
FROM
qual_eval_result
WHERE
eval_year = #{evalYear}
AND eval_quarter = #{evalQuarter}
AND evaluator_id = #{evaluatorId}
AND target_emp_no = #{targetEmpNo}

mapper.insert:
INSERT INTO qual_eval_result ( /* com.flowenect.hr.eval.mapper.EvalMapper.insertQualEvalResults */ result_no , target_emp_no , eval_cd , eval_score , eval_year , eval_quarter , evaluator_id , eval_comment , eval_dtm ) SELECT SEQ_QUAL_EVAL_RESULT_NO.NEXTVAL, A.* FROM (
SELECT #{targetEmpNo} , #{item.evalCd} , #{item.evalScore} , TO_CHAR(SYSDATE, 'YYYY') , CASE WHEN TO_NUMBER(TO_CHAR(SYSDATE, 'MM')) BETWEEN 1 AND 6 THEN '1' ELSE '2' END , #{evaluatorId} , #{item.evalComment} , SYSDATE FROM DUAL
) A

choose.when:
SELECT DISTINCT p.project_no , p.project_nm , p.project_desc , p.project_stat_cd , p.start_dtm , p.end_dtm , e.emp_nm FROM project p INNER JOIN kpi k ON p.project_no = k.proj_no INNER JOIN assign_task t ON k.kpi_no = t.kpi_no INNER JOIN emp e ON t.emp_no = e.emp_no WHERE e.dept_cd = #{deptCd} AND e.emp_no = #{empNo}
AND p.start_dtm <= TO_DATE(#{endDate}, 'YYYY-MM-DD') AND p.end_dtm >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND TO_DATE(#{startDate}, 'YYYY-MM-DD') BETWEEN TRUNC(p.start_dtm) AND TRUNC(p.end_dtm)
AND p.start_dtm <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND p.project_no = #{projectNo}
AND p.project_nm LIKE '%' || #{searchKeyword} || '%'

mapper.insert:
INSERT INTO QUANT_EVAL_RESULT ( /* com.flowenect.hr.eval.mapper.EvalMapper.insertQuantEvalResult */
eval_res_no
	, emp_no
	, eval_year
	, eval_half
	, score_align
	, score_speed
	, score_faith
	, score_reach
	, score_diff
	, ai_summary
	, reg_emp_no
	, reg_dtm
) VALUES (
SEQ_QUANT_EVAL.NEXTVAL 
    , #{empNo}
	, #{evalYear}
	, #{evalHalf}
	, #{scoreAlign}
	, #{scoreSpeed}
	, #{scoreFaith}
	, #{scoreReach}
	, #{scoreDiff}
	, #{aiSummary}
	, #{regEmpNo}
	, SYSDATE
)

mapper.update:
UPDATE QUANT_EVAL_RESULT
   SET REG_COMENT = #{regComent},
       REG_EMP_NO = #{regEmpNo},  
       REG_DTM    = SYSDATE
 WHERE EMP_NO    = #{empNo}
   AND EVAL_YEAR = #{evalYear}
   AND EVAL_HALF = #{evalHalf}

mapper.insert:
INSERT INTO PEER_AI_REPORT (
    REPORT_ID, TARGET_EMP_NO, MODEL_CD, ANALYSIS_TEXT, SIMILARITY, CONSENSUS, REG_DTM
) VALUES (
    SEQ_PEER_AI_REPORT_ID.NEXTVAL, #{targetEmpNo}, #{modelCd}, #{analysisText}, #{similarity}, #{consensus}, SYSDATE
)
